// ---- Tier config (src/config/tiers.js) ----
/** @typedef {Object} Tier
 *  @prop {number} index
 *  @prop {string} name                  // "Desk", "Room", ...
 *  @prop {number} enterTrueRadius       // meters, e.g. 0.05, 0.25, 1.25, 6, 30, 150
 *  @prop {number} cellSizeSim           // spatial-hash cell size in sim units, e.g. 0.8
 *  @prop {number} loadRadiusSim         // 96 for current tier, 140 for scenery
 *  @prop {number} objectsPerChunk       // 72 current / 8 scenery role
 *  @prop {string[]} archetypeIds        // 8 ids into CATALOG
 *  @prop {number} fogDensityK           // fog = k / cameraDistance
 */
export const TIERS /** @type {Tier[]} */; export const RESCALE_S = 0.2;

// ---- Archetype catalog (src/config/catalog.js) ----
/** @typedef {Object} Archetype
 *  @prop {string} id            // "t0_thumbtack"
 *  @prop {number} tier
 *  @prop {(rng: () => number) => THREE.BufferGeometry} buildGeometry  // vertex-colored, merged
 *  @prop {number} radiusSim     // nominal bounding radius in sim units at spawn
 *  @prop {number} radiusJitter  // 0.25 → ±25%
 *  @prop {number} spawnWeight
 *  @prop {number} yOffset       // rest height over ground as fraction of radius
 */
export const CATALOG /** @type {Record<string, Archetype>} */;

// ---- Object store (src/world/objects.js) — SoA, capacity 8192 ----
class ObjectStore {
  px; py; pz; radius;            // Float32Array(8192)
  archetype;                     // Uint16Array — index into archetype table
  tierOf;                        // Uint8Array
  flags;                         // Uint8Array: ALIVE=1, FADING=2, TOMB=4
  instanceSlot;                  // Int32Array — slot in that archetype's InstancedMesh
  alloc() -> i; free(i); forEachAlive(cb);
}

// ---- Spatial hash (src/world/spatialHash.js) ----
class SpatialHash {
  rebuild(store, cellSize);                 // counting-sort into flat Int32Arrays
  insert(i, x, z); remove(i);               // remove = tombstone until next rebuild
  queryBall(x, y, z, r, maxObjR, outI32Scratch) -> count;  // writes indices, returns n
}

// ---- ScaleManager (src/world/scaleManager.js) ----
class ScaleManager {
  worldScale;                   // double; trueRadius = ball.radiusSim * worldScale
  tierIndex;
  maybeTierUp(ball, store, hash, instances, env) -> boolean;  // performs full rescale
  trueRadiusMeters() -> number;
  formatSize() -> string;       // "7.3 cm" | "12.4 m" | "1.02 km"
}

// ---- Events (src/core/events.js) — tiny emitter, payload objects REUSED (read-only in handlers, never retained) ----
'game:start' {}            'game:reset' {}            'game:win' { trueRadius }
'ball:absorb'  { objIndex, archetypeId, trueRadius, count }   // HUD count + grow SFX hook
'ball:grow'    { trueRadius, simRadius }                      // throttled to 10 Hz for HUD
'tier:changed' { tierIndex, name, trueRadius }                // HUD tier banner
'tier:fadeout' { tierIndex }                                  // instances start scale-fade

// ---- Module wiring contract (main.js game loop, fixed 60 Hz) ----
input.poll() -> { forward: -1..1, turn: -1..1, restart: bool }
ballPhysics.step(dt, inputState, hash, store)        // emits ball:absorb via absorb.js
spawner.update(ballPos, scaleMgr.tierIndex)          // amortized chunk diff
scaleMgr.maybeTierUp(...)                            // similarity rescale, between update & render
cameraRig.update(ball)                               // pos = f(ball.pos, ball.radiusSim)
instances.flush()                                    // set needsUpdate flags once
renderer.render(scene, camera)
hud.update()                                         // 10 Hz throttle, textContent diffing

// ---- Stick-to-ball attachment (src/render/ball.js) ----
function attachStuck(objIndex, store, ball):
  dir = normalize(objPos - ball.pos)                       // scratch Vector3
  localPos = ball.quatInverse * (dir * ball.radiusSim)     // contact point in BALL-LOCAL space
  localQuat = ball.quatInverse * lookAlong(dir) * randomYaw(rng)
  slot = stuckRing.next()                                  // ring buffer, cap 512, overwrite oldest
  stuckMesh[archetypeFamily].setMatrixAt(slot, compose(localPos, localQuat, objScale))
  record attachRadius = ball.radiusSim                     // for the 2%-cull
  // mesh is a CHILD of ball Object3D → never updated again; rolls for free

