/** @typedef {{ simRadius:number, worldScale:number, tierIndex:number, transitionT:number }} ScaleState */
// realRadiusMeters = simRadius * worldScale  (the ONLY conversion, used by HUD and growth math)

// ---- Intent (input.js → katamari.js)
/** @typedef {{ x:number, y:number, boost:boolean }} Intent */  // x,y in [-1,1], camera-relative

// ---- EventBus contract (events.js) — exhaustive list
// 'gameStart' {}                      screens → main (reset state, spawn T0)
// 'restart'   {}                      screens → main
// 'absorb'    { archetypeId, sizeReal, combo, newRealRadius }   absorption → hud, sfx, effects, ballMesh
// 'bounce'    { impactSpeed01 }       absorption → cameraRig (shake), sfx
// 'knockOff'  { count }               absorption → effects, sfx
// 'sizeChanged' { realRadiusMeters, progress01ToNextTier }      absorption → hud (every absorb)
// 'tierUp'    { tierIndex, name }     scaleManager → cameraRig (FOV kick), hud (banner+unit roll), scenery (fog crossfade), sfx, effects
// 'rescale'   { k }                   scaleManager → spawner, instances, scenery (mechanical re-derivation; visually no-op)
// 'frameStats' { ms, drawCalls }      loop → hud debug overlay (dev builds)

// ---- Per-frame call order (main.js owns this, plain function calls not events):
// intent = input.read()
// while (accumulator) { katamari.step(intent, dt); absorption.resolve(dt) }
// scaleManager.update()        // tier check + maybeRescale (post-physics, pre-render)
// spawner.update(budgets)      // chunk diff + queued spawn/despawn
// stuckObjects.update(dt)      // attach anims, crust bake step
// cameraRig.update(dt); effects.update(dt); hud is event-driven (no per-frame poll except odometer tween)
// renderer.render()

