// ---- config.js ----
/** @typedef {Object} TierConfig
 *  @property {number} index            // 0..4
 *  @property {string} name             // 'desk' | 'yard' | ...
 *  @property {number} minR             // ball radius (m) at which tier begins
 *  @property {number} maxObjSize       // largest object size in tier (m)
 *  @property {number} spawnCell        // spawn grid cell size (m): 16*4^t
 *  @property {number} hashCell         // spatial hash cell size (m): 4*maxObjSize
 *  @property {[number,number]} objectsPerCell  // min,max count per spawn cell
 */
export const TIERS /** @type {TierConfig[]} */, GROWTH_K, STUCK_CAP, BURY_RATIO,
             ABSORB_RATIO /* 1.4 */, REBASE_DIST /* 2000 */, RUN_SEED, CAMERA = {dist:7, height:3.2, fogNear:60, fogFar:360, far:600};

// ---- catalog.js ----
/** @typedef {Object} ObjectType
 *  @property {string} id               // 'car', 'thumbtack', ...
 *  @property {number} tier             // 0..4
 *  @property {number} sizeM            // nominal bounding diameter (m)
 *  @property {number} jitter           // e.g. 0.25 → ±25% size
 *  @property {number} weight           // relative spawn frequency within tier
 *  @property {() => THREE.BufferGeometry} build  // merged, vertex-colored, unit-size (scaled by sizeM at instance level)
 */
export const CATALOG /** @type {ObjectType[]} */;  export const byTier /** @type {ObjectType[][]} */;

// ---- render/instances.js ----
export const STATE = { FREE:0, WORLD:1, SPAWNING:2, DESPAWNING:3, STUCK:4, EJECT:5 };
/** @typedef {Object} InstanceRec   // stored in flat arrays inside InstancedPool, slot-indexed
 *  @property {number} state, @property {number} typeIdx
 *  @property {number} x,y,z         // world position (WORLD/ANIM states)
 *  @property {number} yaw, size     // size = jittered bounding diameter (m)
 *  @property {string} globalId      // 't:ix:iz:k' (origin-unshifted)
 *  @property {number} animT         // 0..1 for SPAWNING/DESPAWNING/EJECT
 *  @property {THREE.Vector3} localPos, @property {THREE.Quaternion} localQuat  // STUCK only
 *  @property {number} attachR       // ball radius at stick time (STUCK only)
 */
class InstancedPool {
  /** @param {ObjectType} type, @param {number} capacity=512 */
  alloc() /* → slot|-1 */;  free(slot);  setWorld(slot, x,z,yaw,size,globalId);
  update(dt, ball)          /* advances anims + recomposes dirty matrices */;
}

// ---- player.js ----
/** @typedef {Object} Ball
 *  @property {THREE.Vector3} pos, @property {THREE.Vector3} vel
 *  @property {THREE.Quaternion} quat
 *  @property {number} r           // logical radius (m), gameplay truth
 *  @property {number} rVisual     // slewed toward r at ≤1.5r/s, drives camera+mesh
 */
player.update(dt, move /* {x,z} */, camYaw);  player.grow(objSizeM);  player.reset();

// ---- spatialHash.js ----
class SpatialHash { constructor(cellSize); insert(slot,x,z); remove(slot,x,z); queryCircle(x,z,radius,outArray) }

// ---- world.js ----
world.update(dt, ball)        // tier state machine + cell streaming
world.consumeId(globalId); world.applyOriginShift(dx,dz); world.reset(seed);

// ---- events.js bus contract (the ONLY game→HUD channel) ----
emit('state',      {phase:'title'|'playing'})
emit('grow',       {r:number, rVisual:number})                       // every change
emit('absorb',     {typeId:string, sizeM:number, count:number, r:number})
emit('tierchange', {tier:number, name:string})
emit('bonk',       {speed:number, lost:number})

